using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools ---
var notepad = new Notepad();
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Chat client (MEAI abstraction over OpenAI) ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research a topic provided by the user.

        Follow this process:
        1. Break the topic into 2-3 key subtopics or questions.
        2. Use the web_search tool to find information about each subtopic.
        3. Use the save_note tool to record important findings as you go.
        4. After researching, use get_notes to review everything you collected.
        5. Provide a well-organized summary with key findings, citing your sources.

        Be thorough but concise. Always save notes before summarizing.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic: ");

var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research this topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("─── Research Summary ───────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n────────────────────────────────────────");

if (notepad.Count > 0)
{
    Console.WriteLine($"\n📝 {notepad.Count} note(s) were collected during research.");
}

// --- Tool implementations ---

/// <summary>Simulates web search by fetching and extracting text from a search engine.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns relevant text snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
            var html = await s_http.GetStringAsync(url);

            // Extract visible text from the HTML response
            var text = ExtractText(html);

            return string.IsNullOrWhiteSpace(text)
                ? $"No results found for: {query}"
                : $"Search results for '{query}':\n{Truncate(text, 3000)}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static string ExtractText(string html)
    {
        // Strip tags and decode entities for a rough text extraction
        var noTags = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
        var decoded = WebUtility.HtmlDecode(noTags);
        var collapsed = System.Text.RegularExpressions.Regex.Replace(decoded, @"\s+", " ");
        return collapsed.Trim();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

/// <summary>A simple in-memory notepad for the agent to collect findings.</summary>
class Notepad
{
    private readonly List<string> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var result = string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
        return $"Saved notes ({_notes.Count}):\n{result}";
    }
}

